eld_type":"header_field","inspection_marker":"","is_removed_field":false,"is_active":true,"source_page_start":14,"source_page_end":14,"raw_source_text":"Maximum assigned deadweight (metric tonnes):","remarks":""},{"printed_field_no":"1.7","internal_field_no":"01A.007","field_sort_key":1100700.006,"field_label":"Vessel type: (M) Bulk carrier - carrying solid bulk cargos other than grain Bulk carrier - carrying grain cargos General cargo ship - carrying general and/or container cargos Container ship - carrying container cargos","field_type":"header_field","inspection_marker":"M","is_removed_field":false,"is_active":true,"source_page_start":14,"source_page_end":14,"raw_source_text":"Vessel type: (M)\nBulk carrier - carrying solid bulk cargos other than grain\nBulk carrier - carrying grain cargos\nGeneral cargo ship - carrying general and/or container cargos\nContainer ship - carrying container cargos","remarks":""},{"printed_field_no":"1.8","internal_field_no":"01A.008","field_sort_key":1100800.007,"field_label":"Hull type: (M) Double Bottom-Single Skin Side Double Hull","field_type":"header_field","inspection_marker":"M","is_removed_field":false,"is_active":true,"source_page_start":14,"source_page_end":14,"raw_source_text":"Hull type: (M)\nDouble Bottom-Single Skin Side\nDouble Hull","remarks":""},{"printed_field_no":"1.9","internal_field_no":"01A.009","field_sort_key":1100900.008,"field_label":"Vessel’s operation at the time of inspection: Loading Discharging Bunkering At anchor Idle In dry dock / shipyard At sea/river transit Repairs afloat","field_type":"header_field","inspection_marker":"","is_removed_field":false,"is_active":true,"source_page_start":14,"source_page_end":14,"raw_source_text":"Vessel’s operation at the time of inspection:\nLoading\nDischarging\nBunkering\nAt anchor\nIdle\nIn dry dock / shipyard\nAt sea/river transit\nRepairs afloat","remarks":""},{"printed_field_no":"1.10","internal_field_no":"01A.010","field_sort_key":1101000.009,"field_label":"Name of cargo being handled: N/A","field_type":"header_field","inspection_marker":"","is_removed_field":false,"is_active":true,"source_page_start":14,"source_page_end":14,"raw_source_text":"Name of cargo being handled: N/A\nGuide to Inspection\nThis question should be answered N/A when vessel is in ballast condition.\nRefer to shipper declaration and/or dangerous goods declaration to determine the correct name of the cargo.","remarks":""},{"printed_field_no":"1.11","internal_field_no":"01A.011","field_sort_key":1101100.01,"field_label":"Details of Port State Control inspection history for the last 12 months: (M) N/A","field_type":"header_field","inspection_marker":"M","is_removed_field":false,"is_active":true,"source_page_start":14,"source_page_end":14,"raw_source_text":"Details of Port State Control inspection history for the last 12 months: (M) N/A\nGuide to Inspection\nInspector shall record the summary of significant deficiencies and, if the vessel was detained, detainable\ndeficiencies. The records of Port State inspection should be retained on board for at least two years.\nIf the vessel’s name and/or the vessel’s manager changed after the inspection, record the name of vessel\nand/or vessel’s manager at the time of inspection.","remarks":""},{"printed_field_no":"1.12","internal_field_no":"01A.012","field_sort_key":1101200.011,"field_label":"Name of Classification Society: (M) IACS- Classification Society Non-IACS- Classification Society","field_type":"header_field","inspection_marker":"M","is_removed_field":false,"is_active":true,"source_page_start":15,"source_page_end":15,"raw_source_text":"Name of Classification Society: (M)\nIACS- Classification Society\nNon-IACS- Classification Society\nGuide to Inspection\nIf the vessel has dual class, select the name of the classification society issuing the statutory certificates from the\ndrop-down list and the name of the second society in comments.\nIf the vessel has changed class within the past 6 months, record the previous classification society and the date of\nchange as a comment.","remarks":""},{"printed_field_no":"1.13","internal_field_no":"01A.013","field_sort_key":1101300.012,"field_label":"Expiry date of Class Certificate:","field_type":"header_field","inspection_marker":"M","is_removed_field":false,"is_active":true,"source_page_start":15,"source_page_end":15,"raw_source_text":"Expiry date of Class Certificate: (M)","remarks":""},{"printed_field_no":"1.14","internal_field_no":"01A.014","field_sort_key":1101400.013,"field_label":"Date the last Special Survey was completed: (M) N/A","field_type":"header_field","inspection_marker":"M","is_removed_field":false,"is_active":true,"source_page_start":15,"source_page_end":15,"raw_source_text":"Date the last Special Survey was completed: (M) N/A","remarks":""},{"printed_field_no":"1.15","internal_field_no":"01A.015","field_sort_key":1101500.014,"field_label":"Date of last routine dry dock: (M) N/A","field_type":"header_field","inspection_marker":"M","is_removed_field":false,"is_active":true,"source_page_start":15,"source_page_end":15,"raw_source_text":"Date of last routine dry dock: (M) N/A","remarks":""},{"printed_field_no":"1.16","internal_field_no":"01A.016","field_sort_key":1101600.015,"field_label":"Date of unscheduled repair / and or last dry dock: (M) N/A","field_type":"header_field","inspection_marker":"M","is_removed_field":false,"is_active":true,"source_page_start":15,"source_page_end":15,"raw_source_text":"Date of unscheduled repair / and or last dry dock: (M) N/A\nGuide to Inspection\nRecord the reason for unscheduled repair and/or dry dock.","remarks":""},{"printed_field_no":"1.17.1","internal_field_no":"01A.017.001","field_sort_key":1101701.016,"field_label":"Attained EEDI: (M) N/A","field_type":"header_field","inspection_marker":"M","is_removed_field":false,"is_active":true,"source_page_start":15,"source_page_end":15,"raw_source_text":"Attained EEDI: (M) N/A","remarks":""},{"printed_field_no":"1.17.2","internal_field_no":"01A.017.002","field_sort_key":1101702.017,"field_label":"Carbon Intensity Indicator (CII): (M) N/A","field_type":"header_field","inspection_marker":"M","is_removed_field":false,"is_active":true,"source_page_start":15,"source_page_end":15,"raw_source_text":"Carbon Intensity Indicator (CII): (M) N/A\nGuide to Inspection\nThe Carbon Intensity Indicator (CII) is a measure of how efficiently a ship transports goods or passengers and is given\nin grams of CO2 emitted per cargo-carrying capacity and nautical mile. The ship is then given an annual rating ranging\nfrom A to E, whereby the rating thresholds will become increasingly stringent towards 2030.\nThe CII applies to all cargo, RoPax and cruise ships above 5,000 GT. The yearly CII is calculated based on reported IMO\nDCS data and the ship is given a rating from A to E.\nThe Attained EEDI value is listed in Section 3.1 of the supplement to the International Energy Efficiency (IEE) Certificate.\nThe Attained CII and its resulting rating (A-E) are recorded on the Data Collection System (DCS) Statement of Compli-\nance (SoC).","remarks":""},{"printed_field_no":"1.18","internal_field_no":"01A.018","field_sort_key":1101800.018,"field_label":"This question has been removed from the current version of the document.","field_type":"removed","inspection_marker":"","is_removed_field":true,"is_active":false,"source_page_start":15,"source_page_end":15,"raw_source_text":"This question has been removed from the current version of the document.","remarks":""},{"printed_field_no":"1.19","internal_field_no":"01A.019","field_sort_key":1101900.019,"field_label":"Name of the DoC Manager:","field_type":"header_field","inspection_marker":"M","is_removed_field":false,"is_active":true,"source_page_start":15,"source_page_end":15,"raw_source_text":"Name of the DoC Manager: (M)\nGuide to Inspection\nThe name of the DoC Manager is recorded in the vessel’s Document of Compliance.","remarks":""},{"printed_field_no":"1.20","internal_field_no":"01A.020","field_sort_key":1102000.02,"field_label":"Date the current DoC Manager took over the vessel:","field_type":"header_field","inspection_marker":"","is_removed_field":false,"is_active":true,"source_page_start":15,"source_page_end":15,"raw_source_text":"Date the current DoC Manager took over the vessel:\nGuide to Inspection\nThe date of the vessel’s manager taking over the vessel is recorded in the Continuous Synopsis Record.","remarks":""},{"printed_field_no":"1.21","internal_field_no":"01A.021","field_sort_key":1102100.021,"field_label":"Dates of last two visits of the vessel’s manager: (M) 1st Visit: N/A 2nd Visit: N/A","field_type":"header_field","inspection_marker":"M","is_removed_field":false,"is_active":true,"source_page_start":16,"source_page_end":16,"raw_source_text":"Dates of last two visits of the vessel’s manager: (M)\n1st Visit: N/A\n2nd Visit: N/A\nGuide to Inspection\nRecord the position of ship’s manager attending i.e. Marine Superintendent, Engineer Superintendent\nor Naval Architect. The inspector should, under Q 4.3, record a finding if the vessel had not been inspected through a\ncombination of marine and technical superintendent visits at regular intervals, as required by the inspection guide.","remarks":""},{"printed_field_no":"1.22","internal_field_no":"01A.022","field_sort_key":1102200.022,"field_label":"Standard/Hybrid Inspection Name of the Rightship inspector: Dual Inspection Name of lead inspector: Name of Co-Inspector:","field_type":"header_field","inspection_marker":"","is_removed_field":false,"is_active":true,"source_page_start":16,"source_page_end":16,"raw_source_text":"Standard/Hybrid Inspection Name of the Rightship inspector:\nDual Inspection Name of lead inspector:\nName of Co-Inspector:","remarks":""},{"printed_field_no":"1.23","internal_field_no":"01A.023","field_sort_key":1102300.023,"field_label":"Port of inspection:","field_type":"header_field","inspection_marker":"V","is_removed_field":false,"is_active":true,"source_page_start":16,"source_page_end":16,"raw_source_text":"Port of inspection: (V)","remarks":""},{"printed_field_no":"1.24.1","internal_field_no":"01A.024.001","field_sort_key":1102401.024,"field_label":"Standard Date and time inspector arrived at the vessel: (V) Hybrid: Time spent reviewing documentation prior to boarding:(V) Date and time inspector arrived at the vessel: (V) Dual: Date and time inspectors arrived at the vessel:","field_type":"header_field","inspection_marker":"V","is_removed_field":false,"is_active":true,"source_page_start":16,"source_page_end":16,"raw_source_text":"Standard Date and time inspector arrived at the vessel: (V)\nHybrid: Time spent reviewing documentation prior to boarding:(V)\nDate and time inspector arrived at the vessel: (V)\nDual: Date and time inspectors arrived at the vessel:","remarks":""},{"printed_field_no":"1.24.2","internal_field_no":"01A.024.002","field_sort_key":1102402.025,"field_label":"Date and time of starting and completion of opening meeting:","field_type":"header_field","inspection_marker":"V","is_removed_field":false,"is_active":true,"source_page_start":16,"source_page_end":16,"raw_source_text":"Date and time of starting and completion of opening meeting: (V)","remarks":""},{"printed_field_no":"1.24.3","internal_field_no":"01A.024.003","field_sort_key":1102403.026,"field_label":"Date and time of start and completion of closing meeting:","field_type":"header_field","inspection_marker":"V","is_removed_field":false,"is_active":true,"source_page_start":16,"source_page_end":16,"raw_source_text":"Date and time of start and completion of closing meeting: (V)\nGuide to Inspection\nIf this was a hybrid inspection, the inspector shall record in the comments the reason for reviewing the documents on\nboard, if applicable.","remarks":""},{"printed_field_no":"1.25","internal_field_no":"01A.025","field_sort_key":1102500.027,"field_label":"Date and time Rightship inspector left the vessel:","field_type":"header_field","inspection_marker":"V","is_removed_field":false,"is_active":true,"source_page_start":16,"source_page_end":16,"raw_source_text":"Date and time Rightship inspector left the vessel: (V)\nGuide to Inspection\nRecord the arrival and departure time/dates for each session of the inspection (when the inspection was carried\nout in more than one session) or when the inspection was carried out by more than one inspector.","remarks":""},{"printed_field_no":"1.26","internal_field_no":"01A.026","field_sort_key":1102600.028,"field_label":"Total time taken for inspection:","field_type":"header_field","inspection_marker":"V","is_removed_field":false,"is_active":true,"source_page_start":16,"source_page_end":16,"raw_source_text":"Total time taken for inspection: (V)","remarks":""},{"printed_field_no":"1.27","internal_field_no":"01A.027","field_sort_key":1102700.029,"field_label":"Date the inspection was completed:","field_type":"header_field","inspection_marker":"V","is_removed_field":false,"is_active":true,"source_page_start":16,"source_page_end":16,"raw_source_text":"Date the inspection was completed: (V)\nGuide to Inspection\nRecord the actual time of inspection and exclude suspension of inspection for any reason i.e., meals,\nPSC inspection etc.","remarks":""},{"printed_field_no":"1.28","internal_field_no":"01A.028","field_sort_key":1102800.03,"field_label":"Name of the ship’s P&I club:(M) International Group of P&I Non-International Group of P&I","field_type":"header_field","inspection_marker":"M","is_removed_field":false,"is_active":true,"source_page_start":17,"source_page_end":17,"raw_source_text":"Name of the ship’s P&I club:(M)\nInternational Group of P&I\nNon-International Group of P&I\nGuide to Inspection\nThe current list of P&I Clubs that are member of the International Group is provided below.\n> American Steamship Owners Mutual Protection and Indemnity Association, Inc.\n> American Club (Europe)\n> The Britannia Steam Ship Insurance Association Limited\n> The Britannia Steam Ship Insurance Association Europe\n> Gard P.&I. (Bermuda) Limited\n> Assuranceforeningen Gard (Gjensidig)\n> The Japan Ship Owners’ Mutual Protection & Indemnity Association\n> The London Steam-Ship Owners’ Mutual Insurance Association Limited\n> The London P&I Insurance Company (Europe) Limited\n> NorthStandard Limited\n> NorthStandard EU DAC\n> The Standard Club UK Ltd\n> The Standard Club Asia Ltd\n> The Standard Club Ireland DAC\n> The Shipowners’ Mutual Protection & Indemnity Association (Luxembourg)\n> Assuranceforeningen Skuld (Gjensidig)\n> Skuld Mutual Protection and Indemnity Association (Bermuda) Ltd.\n> The Steamship Mutual Underwriting Association (Bermuda) Limited\n> Steamship Mutual Underwriting Association Ltd.\n> Steamship Mutual Underwriting Association (Europe) Limited\n> Sveriges Ångfartygs Assurans Förening / The Swedish Club\n> The United Kingdom Mutual Steam Ship Assurance Association Limited\n> UK P&I (Bermuda)\n> UK P&I (UKNV)\n> The West of England Ship Owners Mutual Insurance Association (Luxembourg)","remarks":""},{"printed_field_no":"1.29.1","internal_field_no":"01A.029.001","field_sort_key":1102901.031,"field_label":"Is the vessel manager a subscriber to the Dry Bulk Centre of Excellence (DBCE)? Yes No Knowledge of This No","field_type":"header_field","inspection_marker":"","is_removed_field":false,"is_active":true,"source_page_start":17,"source_page_end":17,"raw_source_text":"Is the vessel manager a subscriber to the Dry Bulk Centre of Excellence (DBCE)?\nYes No Knowledge of This No","remarks":""},{"printed_field_no":"1.29.2","internal_field_no":"01A.029.002","field_sort_key":1102902.032,"field_label":"Has a DryBMS self-assessment been completed? Yes No Knowledge of This No","field_type":"header_field","inspection_marker":"","is_removed_field":false,"is_active":true,"source_page_start":17,"source_page_end":17,"raw_source_text":"Has a DryBMS self-assessment been completed?\nYes No Knowledge of This No\nGuide to Inspection\nThe inspector is not required to request or review any documentation to validate the Master’s response.","remarks":""}]}$RISQCORE1$::jsonb AS payload
),
qs AS (
  SELECT id AS question_set_id FROM public.risq_question_sets WHERE question_set_code = 'RISQ_3_2' LIMIT 1
),
input_rows AS (
  SELECT *
  FROM payload p
  CROSS JOIN LATERAL jsonb_to_recordset(p.payload->'header_fields') AS r(
    printed_field_no text,
    internal_field_no text,
    field_sort_key numeric,
    field_label text,
    field_type text,
    inspection_marker text,
    is_removed_field boolean,
    is_active boolean,
    source_page_start integer,
    source_page_end integer,
    raw_source_text text,
    remarks text
  )
)
INSERT INTO public.risq_inspection_header_fields (
  question_set_id,
  printed_field_no,
  internal_field_no,
  field_sort_key,
  field_label,
  field_type,
  inspection_marker,
  is_removed_field,
  is_active,
  source_page_start,
  source_page_end,
  raw_source_text,
  remarks,
  created_by,
  updated_by
)
SELECT
  qs.question_set_id,
  i.printed_field_no,
  i.internal_field_no,
  i.field_sort_key,
  i.field_label,
  i.field_type,
  i.inspection_marker,
  i.is_removed_field,
  i.is_active,
  i.source_page_start,
  i.source_page_end,
  i.raw_source_text,
  i.remarks,
  auth.uid(),
  auth.uid()
FROM input_rows i
CROSS JOIN qs
ON CONFLICT (question_set_id, internal_field_no)
DO UPDATE SET
  printed_field_no = EXCLUDED.printed_field_no,
  field_sort_key = EXCLUDED.field_sort_key,
  field_label = EXCLUDED.field_label,
  field_type = EXCLUDED.field_type,
  inspection_marker = EXCLUDED.inspection_marker,
  is_removed_field = EXCLUDED.is_removed_field,
  is_active = EXCLUDED.is_active,
  source_page_start = EXCLUDED.source_page_start,
  source_page_end = EXCLUDED.source_page_end,
  raw_source_text = EXCLUDED.raw_source_text,
  updated_by = auth.uid();

COMMIT;

SELECT
  'RISQ sections and header fields imported.' AS result,
  (SELECT COUNT(*) FROM public.risq_sections s JOIN public.risq_question_sets qs ON qs.id = s.question_set_id WHERE qs.question_set_code = 'RISQ_3_2') AS sections_count,
  (SELECT COUNT(*) FROM public.risq_inspection_header_fields h JOIN public.risq_question_sets qs ON qs.id = h.question_set_id WHERE qs.question_set_code = 'RISQ_3_2') AS header_fields_count;
